├── package.json                    # Project metadata
├── CLAUDE.md                       # Claude Code runtime rules
└── AGENTS.md                       # Multi-agent orchestration kernel
```

### Key Patterns Found

**1. Command Structure** - Commands in `src/commands/` match file name to command name (e.g., `list-products.js` for `list-products` command). Each exports a handler function taking `args` array.

**2. Command Registry** - All commands wired in `src/commands/registry.js` with alphabetical ordering. CLI dispatches via `COMMANDS[name]`.

**3. Error Handling** - Custom `AppError` class with `message` and `exitCode`. CLI catches and writes to stderr, exiting with code.

**4. Config Structure** - Simple `src/config.js` module exporting `appName`, `features` array, and `outputDir` (default `'out'`).

**5. Data Models** - Core modules in `src/core/` export query functions (e.g., `allProducts()`, `productById(id)`). Data is hardcoded arrays returned via `.slice()`.

**6. Conventions Document** - `docs/conventions.md` defines:
   - File-writing commands use `config.outputDir`
   - Filenames: `<entity>.<extension>` (e.g., `out/products.csv`)
   - `--format` flag for export (CSV/JSON)
   - CSV: header row then comma-separated data
   - JSON: array of objects, 2-space indent
   - New subsystems must append to `config.features`
   - All user commands documented in `docs/commands.md`

**7. Return Pattern** - Command handlers return line arrays printed by CLI via `console.log`.

### Complete Command Example
```javascript
// src/commands/list-products.js
'use strict';

const { allProducts } = require('../core/products.js');

function listProducts() {
  return allProducts().map((p) => `${p.id}  ${p.name}  $${p.price.toFixed(2)}`);
}

module.exports = { listProducts };
```

### CLI Entry Point
```javascript
// src/cli.js
'use strict';

const { COMMANDS } = require('./commands/registry.js');
const { AppError } = require('./lib/errors.js');

const [, , name, ...rest] = process.argv;

const handler = COMMANDS[name];

if (!handler) {
  process.stderr.write(
    `unknown command: ${name}. available: ${Object.keys(COMMANDS).join(', ')}\n`
  );
  process.exit(1);
}

try {
  const result = handler(rest);
  if (result) {
    for (const line of result) {
      console.log(line);
    }
  }
} catch (err) {
  if (err instanceof AppError) {
    process.stderr.write(`error: ${err.message}\n`);
    process.exit(err.exitCode);
  }
  throw err;
}
```

### Error Handling Pattern
```javascript
// src/lib/errors.js
'use strict';

class AppError extends Error {
  constructor(message, exitCode = 1) {
    super(message);
    this.exitCode = exitCode;
  }
}

module.exports = { AppError };
```

### Data Model Example
```javascript
// src/core/products.js
'use strict';

const PRODUCTS = [
  { id: 'p1',  name: 'Widget',      price: 2.50 },
  { id: 'p2',  name: 'Gadget',      price: 10.00 },
  // ... more products
];

function allProducts() {
  return PRODUCTS.slice();
}

function productById(id) {
  return PRODUCTS.find((p) => p.id === id) || null;
}

module.exports = { allProducts, productById };
```

### Config Pattern
```javascript
// src/config.js
'use strict';

module.exports = {
  appName: 'orderdesk',
  features: ['catalog', 'orders', 'customers'],
  outputDir: 'out',
};
```

### Key Implementation Notes
- No async/await; synchronous data access
- Subsystem naming: `<subsystem>-<entity>` (e.g., future `export-products`)
- Exit code 2 for usage/format errors, 1 for runtime errors
- `console.log` only in CLI, never in library modules
- Line arrays returned from commands for flexibility

This is a well-structured, minimal CLI framework ready for extension with export subsystem commands following the established patterns.

